class Solution extends SolBase {
    public int rand10() {
        while (true) {
            int a = rand7();
            if (a > 6) continue;
            int b = rand7();
            int num = (a - 1) * 7 + b;
            if (num <= 40) {
                return ((num - 1) % 10) + 1;
            }
        }
    }
}

